// n8n Code node
// Mode: Run Once for All Items

// ===============================
// INPUT VARIABLES (placeholders)
// ===============================

const VIDEO_META = {
  titles: $('read video meta').first().json.videoTitle.toString(),
  descriptions: $('read video meta').first().json.videoDescription.toString(),
};

const INCLUDE_NEIGHBOR_ROUTE = true;
const INCLUDE_NEIGHBOR_TREATMENTS = true;

// ===============================
// HELPERS
// ===============================

function isPlainObject(value) {
  return value !== null && typeof value === "object" && !Array.isArray(value);
}

function clone(value) {
  return value === undefined ? undefined : JSON.parse(JSON.stringify(value));
}

function getSegmentIndex(json, fallbackIndex) {
  if (Number.isInteger(json?.segment_index)) return json.segment_index;
  if (Number.isInteger(json?.segment_meta?.partIndex)) return json.segment_meta.partIndex;
  if (Number.isInteger(json?.segment_meta?.segment_index)) return json.segment_meta.segment_index;
  if (Number.isInteger(json?.segment_analysis?.segment_index)) return json.segment_analysis.segment_index;
  if (Number.isInteger(json?.segment_plan?.segment_index)) return json.segment_plan.segment_index;
  if (Number.isInteger(json?.segment_prompt_route?.segment_index)) return json.segment_prompt_route.segment_index;
  if (Number.isInteger(json?.shot_planning?.segment_index)) return json.shot_planning.segment_index;
  if (Number.isInteger(json?.graphic_treatment_plan?.segment_index)) return json.graphic_treatment_plan.segment_index;
  if (Number.isInteger(json?.still_treatment_plan?.segment_index)) return json.still_treatment_plan.segment_index;
  return fallbackIndex;
}

function getTopLevelObject(json, key) {
  return isPlainObject(json?.[key]) ? json[key] : null;
}

function makeOutputFileName(sourceFileName, segmentIndex) {
  if (typeof sourceFileName === "string" && sourceFileName.length > 0) {
    return sourceFileName.replace(/\.json$/i, "_generationContext.json");
  }
  return `${String(segmentIndex).padStart(5, "0")}_generationContext.json`;
}

// ===============================
// MAIN
// ===============================

const items = $input.all();

const normalized = items.map((item, originalIndex) => {
  const json = item.json ?? {};
  const segmentIndex = getSegmentIndex(json, originalIndex);

  return {
    originalIndex,
    segment_index: segmentIndex,
    source_file_name: typeof json.fileName === "string" ? json.fileName : "",

    segment_meta: getTopLevelObject(json, "segment_meta"),
    segment_analysis: getTopLevelObject(json, "segment_analysis"),
    segment_plan: getTopLevelObject(json, "segment_plan"),
    segment_prompt_route: getTopLevelObject(json, "segment_prompt_route"),
    shot_planning: getTopLevelObject(json, "shot_planning"),
    graphic_treatment_plan: getTopLevelObject(json, "graphic_treatment_plan"),
    still_treatment_plan: getTopLevelObject(json, "still_treatment_plan"),
  };
});

const sorted = [...normalized].sort((a, b) => a.segment_index - b.segment_index);

const resultByOriginalIndex = new Map();

for (let i = 0; i < sorted.length; i++) {
  const current = sorted[i];
  const prev = sorted[i - 1] ?? null;
  const next = sorted[i + 1] ?? null;

  const outputJson = {
    schema_version: "1.0",
    segment_index: current.segment_index,

    video_meta: clone(VIDEO_META),

    segment_meta: clone(current.segment_meta),
    segment_analysis: clone(current.segment_analysis),
    segment_plan: clone(current.segment_plan),
    segment_prompt_route: clone(current.segment_prompt_route),

    shot_planning: clone(current.shot_planning),
    graphic_treatment_plan: clone(current.graphic_treatment_plan),
    still_treatment_plan: clone(current.still_treatment_plan),

    prev_segment_meta: prev ? clone(prev.segment_meta) : null,
    next_segment_meta: next ? clone(next.segment_meta) : null,

    prev_segment_plan: prev ? clone(prev.segment_plan) : null,
    next_segment_plan: next ? clone(next.segment_plan) : null,
  };

  if (INCLUDE_NEIGHBOR_ROUTE) {
    outputJson.prev_segment_prompt_route = prev ? clone(prev.segment_prompt_route) : null;
    outputJson.next_segment_prompt_route = next ? clone(next.segment_prompt_route) : null;
  }

  if (INCLUDE_NEIGHBOR_TREATMENTS) {
    outputJson.prev_shot_planning = prev ? clone(prev.shot_planning) : null;
    outputJson.next_shot_planning = next ? clone(next.shot_planning) : null;

    outputJson.prev_graphic_treatment_plan = prev ? clone(prev.graphic_treatment_plan) : null;
    outputJson.next_graphic_treatment_plan = next ? clone(next.graphic_treatment_plan) : null;

    outputJson.prev_still_treatment_plan = prev ? clone(prev.still_treatment_plan) : null;
    outputJson.next_still_treatment_plan = next ? clone(next.still_treatment_plan) : null;
  }

  outputJson.fileName = makeOutputFileName(current.source_file_name, current.segment_index);

  resultByOriginalIndex.set(current.originalIndex, { json: outputJson });
}

return items.map((_, originalIndex) => {
  return resultByOriginalIndex.get(originalIndex) ?? {
    json: {
      schema_version: "1.0",
      segment_index: originalIndex,
      video_meta: clone(VIDEO_META),
      segment_meta: null,
      segment_analysis: null,
      segment_plan: null,
      segment_prompt_route: null,
      shot_planning: null,
      graphic_treatment_plan: null,
      still_treatment_plan: null,
      prev_segment_meta: null,
      next_segment_meta: null,
      prev_segment_plan: null,
      next_segment_plan: null,
      prev_segment_prompt_route: null,
      next_segment_prompt_route: null,
      prev_shot_planning: null,
      next_shot_planning: null,
      prev_graphic_treatment_plan: null,
      next_graphic_treatment_plan: null,
      prev_still_treatment_plan: null,
      next_still_treatment_plan: null,
      fileName: `${String(originalIndex).padStart(5, "0")}_generationContext.json`,
    }
  };
});

